#include <bits/stdc++.h>
using namespace std;
int main()
{
    int n,m,a[100005],b[100005];
    cin>>n>>m;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
    }
    for(int i=1;i<=m;i++)
    {
        cin>>b[i];
    }
    sort(b+1,b+m+1);

    int l,r,mid;
    for(int i=1;i<=n;i++)
    {
        int temp=a[i];
        l=1;
        r=m;
        while(l<=r)
        {
            mid=(l+r)/2;
            if(b[mid]>temp)
            {
                r=mid-1;
            }
            else if(b[mid]<temp)
            {
                l=mid+1;
            }
            else
            {
                cout<<temp<<" ";
                break;
            }
        }
    }
    return 0;
}
